	"github.com/utilitywarehouse/telecom-mobile/services/handset/internal/models"
)

var _ = Describe("expireContractsRunner", func() {
	var (
		ctrl         *gomock.Controller
		mockStore    *mockJobs.MockStorage
		mockProducer *mockJobs.MockProducer
		ctx          context.Context
		runnerFunc   func(ctx context.Context)
	)

	BeforeEach(func() {
		ctrl = gomock.NewController(GinkgoT())
		mockStore = mockJobs.NewMockStorage(ctrl)
		mockProducer = mockJobs.NewMockProducer(ctrl)
		ctx = context.Background()
		runnerFunc = expireContractsRunner(mockStore, mockProducer)
	})

	AfterEach(func() {
		ctrl.Finish()
	})

	When("no contracts are expired", func() {
		It("does not produce any events", func() {
			mockStore.EXPECT().FindAndUpdateExpiredContracts(gomock.Any()).
				Return([]models.Contract{}, nil)
			// No producer call expected
			runnerFunc(ctx)
		})
	})

	When("an error occurs before any contracts have been marked as expired", func() {
		It("does not produce any events", func() {
			mockStore.EXPECT().FindAndUpdateExpiredContracts(gomock.Any()).
				Return([]models.Contract{}, errors.New("badness"))
			// No producer call expected
			runnerFunc(ctx)
		})
	})

	// Helper function to create a bunch of contracts with expected producer calls
	setupContracts := func(count int, store mockJobs.MockStorage, producer mockJobs.MockProducer) []models.Contract {
		now := time.Now()
		contracts := make([]models.Contract, count)
		for i := range count {
			id, err := uuid.NewRandom()
			Expect(err).NotTo(HaveOccurred())

			contracts[i] = models.Contract{
				ID:         id,
				ServiceID:  "service-" + id.String(),
				CustomerID: "customer-" + id.String(),
				HandsetID:  "handset-" + id.String(),
				ExpiresAt:  &now,
				Status:     models.ContractStatusExpired,
			}

			mockProducer.EXPECT().ProduceMobileHandsetContractExpiredSync(gomock.Any(), &serviceevents.MobileHandsetContractExpired{
				ServiceId:  "service-" + id.String(),
				CustomerId: "customer-" + id.String(),
				ContractId: id.String(),
				HandsetId:  "handset-" + id.String(),
				ExpiresAt:  timestamppb.New(now),
			})
		}

		return contracts
	}

	When("contracts have been expired with no errors", func() {
		It("produces one event per contract", func() {
			contracts := setupContracts(10, *mockStore, *mockProducer)
			mockStore.EXPECT().FindAndUpdateExpiredContracts(gomock.Any()).
				Return(contracts, nil)

			runnerFunc(ctx)
		})
	})

	When("contracts have been expired with an error", func() {
		It("still does produces one event per contract", func() {
			contracts := setupContracts(100, *mockStore, *mockProducer)
			mockStore.EXPECT().FindAndUpdateExpiredContracts(gomock.Any()).
				Return(contracts, errors.New("badness"))

			runnerFunc(ctx)
		})
	})
})
