func (s storage) updateContractStatus(ctx context.Context, filter bson.M, status models.ContractStatus, currentStatuses ...models.ContractStatus) error {
	if len(currentStatuses) == 1 {
		filter["status"] = currentStatuses[0]
	} else if len(currentStatuses) > 1 {
		filter["status"] = bson.M{"$in": currentStatuses}
	}
	update := bson.M{
		"$set": bson.M{
			"status":    status,
			"updatedAt": time.Now(),
		},
	}

	result, err := s.contractsCollection.UpdateOne(ctx, filter, update)
	if err != nil {
		return fmt.Errorf("could not update contract status: %w", err)
	}
	if result.MatchedCount == 0 {
		if len(currentStatuses) > 0 {
			return terrors.ErrConflict
		}
		return terrors.ErrNotFound
	}
	return nil
}

func (s storage) UpdateContractEligibilityApproved(ctx context.Context, requestID string, outcome models.EligibilityOutcome) error {
	setFields := bson.M{
		"status":    models.ContractStatusEligibilityApproved,
		"updatedAt": time.Now(),
	}
	if outcome.Decision != "" {
		setFields["decision"] = outcome.Decision
	}
	if outcome.AgreementID != "" {
		setFields["agreementId"] = outcome.AgreementID
	}
	if outcome.DocusignEnvelopeID != "" {
		setFields["docusignEnvelopeId"] = outcome.DocusignEnvelopeID
	}
	if outcome.CompletedAt != nil {
		setFields["completedAt"] = outcome.CompletedAt
	}

	filter := bson.M{
		"requestId": requestID,
		"status":    models.ContractStatusPendingEligibility,
	}

	var update any
	if outcome.SignedAt != nil {
		setFields["signedAt"] = outcome.SignedAt
		setFields["expiresAt"] = bson.M{
			"$dateAdd": bson.M{
				"startDate": outcome.SignedAt,
				"unit":      "month",
				"amount":    bson.M{"$toInt": "$contractMonths"},
			},
		}
		update = mongo.Pipeline{bson.D{{Key: "$set", Value: setFields}}}
	} else {
		update = bson.M{"$set": setFields}
	}
	result, err := s.contractsCollection.UpdateOne(ctx, filter, update)
	if err != nil {
		return fmt.Errorf("could not update contract eligibility: %w", err)
	}
	if result.MatchedCount == 0 {
		return terrors.ErrConflict
	}
	return nil
}

func (s storage) UpdateContractEligibilityFailed(ctx context.Context, requestID string, outcome models.EligibilityFailureOutcome) error {
	setFields := bson.M{
		"status":    models.ContractStatusDeclined,
		"updatedAt": time.Now(),
	}
	if outcome.FailureReason != "" {
		setFields["failureReason"] = outcome.FailureReason
	}
	if outcome.FailureStage != "" {
		setFields["failureStage"] = outcome.FailureStage
	}
	if outcome.FailureMessage != "" {
		setFields["failureMessage"] = outcome.FailureMessage
	}
	if outcome.FailedAt != nil {
		setFields["failedAt"] = outcome.FailedAt
	}

	filter := bson.M{
		"requestId": requestID,
		"status":    models.ContractStatusPendingEligibility,
	}
	result, err := s.contractsCollection.UpdateOne(ctx, filter, bson.M{"$set": setFields})
	if err != nil {
		return fmt.Errorf("could not update contract eligibility failure: %w", err)
	}
	if result.MatchedCount == 0 {
		return terrors.ErrConflict
	}
	return nil
}

// FindAndUpdateExpiredContracts This will return list of processed contracts even if it errors
func (s storage) FindAndUpdateExpiredContracts(ctx context.Context) ([]models.Contract, error) {
	now := s.nowFunc()
	filter := bson.M{
		"status":    models.ContractStatusHandsetOrdered,
		"expiresAt": bson.M{"$lte": now},
	}
	update := bson.M{
		"$set": bson.M{
			"status":    models.ContractStatusExpired,
			"updatedAt": now,
		},
	}
	opts := options.FindOneAndUpdate().SetReturnDocument(options.After)

	var expired []models.Contract
	for range 100 {
		if err := ctx.Err(); err != nil {
			return expired, err
		}
		var contract models.Contract
		err := s.contractsCollection.FindOneAndUpdate(ctx, filter, update, opts).Decode(&contract)
		if errors.Is(err, mongo.ErrNoDocuments) {
			break
		}
		if err != nil {
			return expired, fmt.Errorf("could not expire contract: %w", err)
		}
		expired = append(expired, contract)
	}

	return expired, nil
}

